import { APPLICATIONS } from "../config/apps.js";
import { config } from "../config/index.js";

/**
 * Check if a URL matches a specific allowed origin or prefix
 * @param {URL} targetUrlObj - The URL object to check
 * @param {string} allowed - The allowed origin or URL prefix
 * @returns {boolean}
 */
const isMatch = (targetUrlObj, allowed) => {
  try {
    const allowedUrlObj = new URL(allowed);

    // 1. If allowed is just an origin (no path), match origin
    if (allowedUrlObj.pathname === "/" && targetUrlObj.pathname !== "/") {
      return targetUrlObj.origin === allowedUrlObj.origin;
    }

    // 2. If allowed has path, target must start with allowed
    return targetUrlObj.href.startsWith(allowed);
  } catch (e) {
    // If allowed is not a valid URL (e.g. just a domain?), fallback to string match
    return false;
  }
};

/**
 * Validate if the redirect target is safe
 * @param {string} targetUrl 
 * @returns {boolean}
 */
export const isValidRedirectTarget = (targetUrl) => {
  if (!targetUrl) return false;

  try {
    const url = new URL(targetUrl);

    // 1. Check against config.allowedDomains (Suffix Match)
    // e.g. .iasbt.com matches sub.iasbt.com
    const isAllowedDomain = config.allowedDomains.some(domain => {
      if (domain.startsWith(".")) {
        return url.hostname.endsWith(domain) || url.hostname === domain.substring(1);
      }
      return url.hostname === domain;
    });

    if (isAllowedDomain) {
      return true;
    }

    // 2. Check against Registered Applications
    for (const app of Object.values(APPLICATIONS)) {
      if (app.allowedOrigins && Array.isArray(app.allowedOrigins)) {
        // Strict check: targetUrl must match one of the allowed origins/URLs
        // or be a sub-path of an allowed URL
        const matched = app.allowedOrigins.some(allowed => {
            // Exact match
            if (allowed === targetUrl) return true;

            // Origin match
            try {
                const allowedOrigin = new URL(allowed).origin;
                if (url.origin === allowedOrigin) return true;
            } catch (e) {
                // ignore invalid allowed origin
            }

            return false;
        });

        if (matched) return true;
      }
    }

    return false;
  } catch (e) {
    // Invalid URL format
    return false;
  }
};

import jwt from "jsonwebtoken";
import pool from "../db.js";
import { config } from "../config/index.js";

// Helper to get signing key/secret based on algorithm
const getSigningKey = () => {
  if (config.jwt.algorithm === "RS256") {
    return config.jwt.privateKey;
  }
  return config.ssoSecret;
};

// Helper to get verification key/secret based on algorithm
const getVerificationKey = () => {
  if (config.jwt.algorithm === "RS256") {
    return config.jwt.publicKey;
  }
  return config.ssoSecret;
};

export const verifyAppToken = async (token) => {
  try {
    // 1. Verify Signature
    // If RS256, use Public Key. If HS256, use Secret.
    // Note: We removed the logic that looked up App Secret based on 'aud'.
    // Reason: All tokens issued by Account Service should be signed by Account Service (Private Key or SSO Secret).
    // App Secrets are only for Client Credentials or specific App-signed tokens (not supported here).

    return jwt.verify(token, getVerificationKey(), { algorithms: [config.jwt.algorithm] });
  } catch (err) {
    console.error("Token verification failed:", err.message);
    return null;
  }
};

export const signToken = (payload, ttlSeconds, secret = null) => {
  const signingKey = secret || getSigningKey();
  if (!signingKey) return null;

  try {
    return jwt.sign(payload, signingKey, { 
      expiresIn: ttlSeconds,
      algorithm: config.jwt.algorithm
    });
  } catch (err) {
    console.error("Sign Token Error:", err);
    return null;
  }
};

export const verifyToken = async (token, secret = null) => {
  const verificationKey = secret || getVerificationKey();
  if (!verificationKey) return null;

  try {
    return jwt.verify(token, verificationKey, { algorithms: [config.jwt.algorithm] });
  } catch (err) {
    return null;
  }
};

export const generateToken = (user) => {
  return signToken({ 
    sub: user.id, 
    name: user.name || user.username, 
    email: user.email,
    isAdmin: user.is_admin || false
  }, 7 * 24 * 60 * 60); // 7 days
};

import { getRedisClient } from "./redis.js";

// In-memory fallback for development/testing when Redis is unavailable
const memoryStore = new Map();

export const setVerificationCode = async (email, code) => {
  try {
    const redis = getRedisClient();
    if (redis.status === 'ready') {
      await redis.set(`verify:${email}`, code, "EX", 300);
    } else {
      console.warn("[VerificationStore] Redis not ready, using memory store");
      memoryStore.set(email, { code, expires: Date.now() + 300000 });
    }
  } catch (error) {
    console.error("[VerificationStore] Set error:", error);
    // Fallback to memory
    memoryStore.set(email, { code, expires: Date.now() + 300000 });
  }
};

export const getVerificationCode = async (email) => {
  // 1. Magic Code for Development/Testing
  if (process.env.NODE_ENV !== 'production' && email.startsWith('test')) {
     return { code: '123456', expires: Date.now() + 3600000 };
  }

  try {
    const redis = getRedisClient();
    if (redis.status === 'ready') {
      const code = await redis.get(`verify:${email}`);
      if (!code) return null;
      return { code, expires: Date.now() + 300000 }; // Redis handles expiry, return valid time
    }
  } catch (error) {
    console.warn("[VerificationStore] Redis error, checking memory store");
  }

  // Fallback to memory store
  const data = memoryStore.get(email);
  if (!data) return null;
  if (Date.now() > data.expires) {
    memoryStore.delete(email);
    return null;
  }
  return data;
};

export const deleteVerificationCode = async (email) => {
  try {
    const redis = getRedisClient();
    if (redis.status === 'ready') {
      await redis.del(`verify:${email}`);
    }
  } catch (e) { /* ignore */ }

  memoryStore.delete(email);
};
